SELECT , p.id as pid, p.name as pname, d.id as did, d.name as dname
FROM interview i
LEFT JOIN position p ON i.positionId = p.id
LEFT JOIN department d ON i.departmentId = d.id


    AND i.candidateName LIKE CONCAT('%',#{interview.candidateName},'%')


    AND i.interviewStatus = #{interview.interviewStatus}


    AND i.result = #{interview.result}


    AND i.positionId = #{interview.positionId}


    AND i.departmentId = #{interview.departmentId}


    AND i.interviewType = #{interview.interviewType}


ORDER BY i.interviewTime DESC

  LIMIT #{page}, #{size}

SELECT COUNT(*) FROM interview i


    AND i.candidateName LIKE CONCAT('%',#{interview.candidateName},'%')


    AND i.interviewStatus = #{interview.interviewStatus}


    AND i.result = #{interview.result}


    AND i.positionId = #{interview.positionId}


    AND i.departmentId = #{interview.departmentId}

SELECT p.name as positionName, COUNT(*) as totalCount, SUM(CASE WHEN i.result = '通过' THEN 1 ELSE 0 END) as passCount, SUM(CASE WHEN i.result = '未通过' THEN 1 ELSE 0 END) as failCount, SUM(CASE WHEN i.result = '待定' THEN 1 ELSE 0 END) as pendingCount FROM interview i LEFT JOIN position p ON i.positionId = p.id
AND i.interviewTime >= #{startDate}
AND i.interviewTime <= #{endDate}
GROUP BY i.positionId, p.name

