UPDATE interview
resumeId = #{resumeId}, candidateName = #{candidateName}, positionId = #{positionId}, departmentId = #{departmentId}, interviewTime = #{interviewTime}, interviewLocation = #{interviewLocation}, interviewerId = #{interviewerId}, interviewerName = #{interviewerName}, interviewType = #{interviewType}, interviewStatus = #{interviewStatus}, result = #{result}, score = #{score}, advantages = #{advantages}, disadvantages = #{disadvantages}, suggestion = #{suggestion}, attachmentPath = #{attachmentPath}, notifyStatus = #{notifyStatus}, notifyWay = #{notifyWay}, remark = #{remark}, updateTime = NOW()
WHERE id = #{id,jdbcType=INTEGER}
